CREATE TABLE `artifacts` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `background_story` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` varchar(80) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `image_label` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
  `shape_tags` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `title` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
  `culture` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `department` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `external_object_id` bigint DEFAULT NULL,
  `external_source` varchar(60) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `image_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_public_domain` bit(1) DEFAULT NULL,
  `thumbnail_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `turtle_question` text COLLATE utf8mb4_unicode_ci,
  `background_story_zh` text COLLATE utf8mb4_unicode_ci,
  `description_zh` text COLLATE utf8mb4_unicode_ci,
  `image_label_zh` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `title_zh` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `turtle_question_zh` text COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id`),
  UNIQUE KEY `UKdfr5m62f1elcg3ct05kkm63v7` (`title`)
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
